+/**
+ * Federation Hub Client - WebSocket client for agent-to-hub communication
+ */
+
+import WebSocket from 'ws';
+import { logger } from '../utils/logger.js';
+// AgentDB is optional - federation works with SQLite only
+type AgentDB = any;
+
+export interface HubClientConfig {
+  endpoint: string;
+  agentId: string;
+  tenantId: string;
+  token: string;
+}
+
+export interface SyncMessage {
+  type: 'auth' | 'pull' | 'push' | 'ack' | 'error';
+  agentId?: string;
+  tenantId?: string;
+  token?: string;
+  vectorClock?: Record<string, number>;
+  data?: any[];
+  error?: string;
+  timestamp: number;
+}
+
+export class FederationHubClient {
+  private config: HubClientConfig;
+  private ws?: WebSocket;
+  private connected: boolean = false;
+  private vectorClock: Record<string, number> = {};
+  private lastSyncTime: number = 0;
+  private messageHandlers: Map<string, (msg: SyncMessage) => void> = new Map();
+
+  constructor(config: HubClientConfig) {
+    this.config = config;
+  }
+
+  /**
+   * Connect to hub with WebSocket
+   */
+  async connect(): Promise<void> {
+    return new Promise((resolve, reject) => {
+      try {
+        // Convert quic:// to ws:// for WebSocket connection
+        const wsEndpoint = this.config.endpoint
+          .replace('quic://', 'ws://')
+          .replace(':4433', ':8443'); // Map QUIC port to WebSocket port
+
+        logger.info('Connecting to federation hub', {
+          endpoint: wsEndpoint,
+          agentId: this.config.agentId
+        });
+
+        this.ws = new WebSocket(wsEndpoint);
+
+        this.ws.on('open', async () => {
+          logger.info('WebSocket connected, authenticating...');
+
+          // Send authentication
+          await this.send({
+            type: 'auth',
+            agentId: this.config.agentId,
+            tenantId: this.config.tenantId,
+            token: this.config.token,
+            vectorClock: this.vectorClock,
+            timestamp: Date.now()
+          });
+
+          // Wait for auth acknowledgment
+          const authTimeout = setTimeout(() => {
+            reject(new Error('Authentication timeout'));
+          }, 5000);
+
+          const authHandler = (msg: SyncMessage) => {
+            if (msg.type === 'ack') {
+              clearTimeout(authTimeout);
+              this.connected = true;
+              this.lastSyncTime = Date.now();
+              logger.info('Authenticated with hub');
+              resolve();
+            } else if (msg.type === 'error') {
+              clearTimeout(authTimeout);
+              reject(new Error(msg.error || 'Authentication failed'));
+            }
+          };
+
+          this.messageHandlers.set('auth', authHandler);
+        });
+
+        this.ws.on('message', (data: Buffer) => {
+          try {
+            const message: SyncMessage = JSON.parse(data.toString());
+            this.handleMessage(message);
+          } catch (error: any) {
+            logger.error('Failed to parse message', { error: error.message });
+          }
+        });
+
+        this.ws.on('close', () => {
+          this.connected = false;
+          logger.info('Disconnected from hub');
+        });
+
+        this.ws.on('error', (error) => {
+          logger.error('WebSocket error', { error: error.message });
+          reject(error);
+        });
+
+      } catch (error: any) {
+        logger.error('Failed to connect to hub', { error: error.message });
+        reject(error);
+      }
+    });
+  }
+
+  /**
+   * Handle incoming message
+   */
