+    return episodes.map((row: any) => ({
+      id: row.id,
+      agentId: row.agent_id,
+      sessionId: row.session_id,
+      task: row.task,
+      input: row.input,
+      output: row.output,
+      reward: row.reward,
+      critique: row.critique,
+      success: row.success === 1,
+      tokensUsed: row.tokens_used,
